import { VmNamedVariableSchema, VmStructSchema, vmTypeFromString, VmVariableSchema } from '../../types/index.js';
export function vmStructSchemaFromRpcResult(r) {
    const schema = new VmStructSchema();
    schema.fields = [];
    const fields = r?.fields ?? [];
    for (const f of fields) {
        const name = String(f?.name ?? '');
        if (!name)
            continue;
        const t = f.schema?.type;
        let vmType;
        if (typeof t === 'number')
            vmType = t;
        else if (typeof t === 'string')
            vmType = vmTypeFromString(t);
        else
            continue;
        schema.fields.push(new VmNamedVariableSchema(name, vmType));
    }
    return schema;
}
export function vmVariableSchemaFromRpcResult(v) {
    const typeVal = v?.type;
    let vmType;
    if (typeof typeVal === 'number')
        vmType = typeVal;
    else if (typeof typeVal === 'string')
        vmType = vmTypeFromString(typeVal);
    else
        throw new Error('Invalid VmVariableSchemaResult.type');
    const vs = new VmVariableSchema(vmType);
    // If nested struct schema is present, convert recursively
    if (v.schema) {
        vs.structure = vmStructSchemaFromRpcResult(v.schema);
    }
    return vs;
}
